import{_ as t,o as r,c as e,ai as o}from"./chunks/framework.CEhIufms.js";const d=JSON.parse('{"title":"About","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),n={name:"about.md"};function s(p,a,i,h,l,u){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>YCup 是一个旨在服务上海市曹杨第二中学学生的公益性组织，致力于提供高质量的数学训练资源并举办线下年级比赛。</p><h2 id="条款" tabindex="-1">条款 <a class="header-anchor" href="#条款" aria-label="Permalink to &quot;条款&quot;">​</a></h2><p>以下条款适用于参加 YCup 的所有参赛者。</p><p>参赛者应自觉遵守校纪校规、公序良俗和法律法规。组委会保留对违反该条例的选手永久的、不可撤销的夺权权力。</p><p>参赛者可以提交数学答案，并保留提交答案中所有知识产权和工业产权（包括道德权利）的所有权。作为提交的条件，参赛者授予 YCup 委员会一项永久的、不可撤销的、全球性、免版税且非独占的许可，允许其使用、复制、改编、修改、出版、分发、公开展示、创作衍生作品及公开展示。</p><p>参赛者以题目自身为基础提交答案，不作任何明示或暗示的保证或条件，包括但不限于任何标题、非侵权、可销性或特定用途适用性的保证或条件。</p><h2 id="成员" tabindex="-1">成员 <a class="header-anchor" href="#成员" aria-label="Permalink to &quot;成员&quot;">​</a></h2><p>联合创始人：<strong>王韬淳，卓成杰，王以</strong></p><p>组委会组长：<strong>王韬淳</strong>，组员：<strong>卓成杰</strong></p><p>科学委员会组长：<strong>卓成杰</strong>，组员：<strong>陈洛炜，王以</strong></p><p>技术委员会组长：<strong>朱修齐</strong>，组员：<strong>王韬淳</strong></p><p>吉祥物：<strong>王以</strong></p><h2 id="信息" tabindex="-1">信息 <a class="header-anchor" href="#信息" aria-label="Permalink to &quot;信息&quot;">​</a></h2><p>官方存档网站：<a href="http://20.219.50.5/ycup-archive/" target="_blank" rel="noreferrer">http://20.219.50.5/ycup-archive/</a></p><p>联系方式：微信 wangtaochun805，QQ 1948735630</p>',17)])])}const _=t(n,[["render",s]]);export{d as __pageData,_ as default};
